function p.main(frame) local args = frame:getParent().args local cell_args = {} for i, v in ipairs(args) do v = v:gsub('^%s+(%S+)%s*$',' %1') local args_v = args[v] local cell_x = {} if cells[v] then cell_x.box = nil else if args_v then cell_x.text = args_v else cell_x.text = '{{{'..v..'}}}' end cell_x.box = true cell_x.colspan = args['colspan_'..v] or args.colspan or '6' cell_x.rowspan = args['rowspan_'..v] or args.rowspan or '2' cell_x.thick = args['border_'..v] or args.border or '2' cell_x.thick = args['boxstyle_'..v] or args.boxstyle or '' end table.insert(cell_args,cell_x) end
return p._main(cell_args) end
