function p.main(frame) local args = frame:getParent().args local cell_args = {} for i, v in ipairs(args) do v = mw.text.trim(v:gsub('^%s+$','$')) local cell_x = {} if cells[v..'t'] then cell_x.box = nil else local args_v = args[v] if args_v then cell_x.text = args_v else cell_x.text = '{{{'..v..'}}}' end cell_x.box = true cell_x.colspan = args['colspan_'..v] or args.colspan or '6' cell_x.rowspan = args['rowspan_'..v] or args.rowspan or '2' cell_x.thick = args['border_'..v] or args.border or '2' cell_x.thick = args['boxstyle_'..v] or args.boxstyle or '' end table.insert(cell_args,cell_x) end
