function p.main(frame) local args = frame:getParent().args local cell_args = {} for i, v in ipairs(args) do v = mw.text.trim(v) if not v:find('%S') then v = '$' end local cell_x = { } if cells[v..'t'] then cell_x.box = nil cell_x.name = v..'t' else cell_x.name = mw.text.trim(v) local args_v = args[cell_x.name] if args_v then cell_x.text = args_v else cell_x.text = '{{{'..v..'}}}' end cell_x.box = true cell_x.colspan = args['colspan_'..v] or args.colspan or '6' cell_x.rowspan = args['rowspan_'..v] or args.rowspan or '2' cell_x.thick = args['border_'..v] or args.border or '2' cell_x.css = args['boxstyle_'..v] or args.boxstyle or '' end table.insert(cell_args,cell_x) end
