function p.main(frame) local args = frame:getParent().args local cell_args = {} for i, v in ipairs(args) do v = mw.text.trim(v) if not v:find('%S') then v = '$' end local cell_x = { } if cells[v..'t'] then cell_x.box = nil cell_x.name = v..'t' else cell_x.name = mw.text.trim(v) local args_v = args[cell_x.name] if args_v then cell_x.text = args_v else cell_x.text = '{{{'..v..'}}}' end cell_x.box = true cell_x.colspan = args['colspan_'..v] or args.colspan or '6' cell_x.rowspan = args['rowspan_'..v] or args.rowspan or '2' cell_x.thick = args['border_'..v] or args.border or '2' cell_x.css = args['boxstyle_'..v] or args.boxstyle or '' end table.insert(cell_args,cell_x) end
return cell_args[1].name .. '^^' --p._main(cell_args) end
function p._main(cell_args) local ret = mw.html.create('tr') :css({ ['height'] = '1px', ['text-align'] = 'center' }) for i, v in ipairs(cell_args) do if v.box then ret:node(make_box(v)) else ret:node(make_cell(v.name)) end end return ret:done() end
function make_cell(name) local props = cells[name] if not props then return end local ret = '' for i, v in ipairs(props) do ret = ret .. tostring(make_tag(v)) end return ret end
function make_tag(tbl) local ret = mw.html.create(tbl.tag) if tbl.style then for n, s in pairs(tbl.style) do ret:css(n,s) end end if tbl.attr then for n, s in pairs(tbl.attr) do ret:attr(n,s) end end if tbl.node then ret:node(make_tag(tbl.node)) end return ret:done() end
function make_box(tbl) local ret = mw.html.create('td') :attr('colspan',tbl.colspan) :attr('rowspan',tbl.rowspan) :css({ ['padding'] = '0.2em', ['border'] = tbl.thick .. 'px solid black' }) :cssText(tbl.css) :wikitext(tbl.text) :done() return ret end
return p

